+		this.credentialsUri = credentialsUri;
+	}
+
+	public boolean isVertexAi() {
+		return this.vertexAi;
+	}
+
+	public void setVertexAi(boolean vertexAi) {
+		this.vertexAi = vertexAi;
+	}
+
+}
