+		contextRunner
+			.withConfiguration(AutoConfigurations.of(GoogleGenAiTextEmbeddingAutoConfiguration.class,
+					GoogleGenAiEmbeddingConnectionAutoConfiguration.class))
+			.withPropertyValues("spring.ai.model.embedding.text=none")
+			.run(context -> {
