+		/**
+		 * Specifies the given text is a query in a search/retrieval setting.
+		 */
+		RETRIEVAL_DOCUMENT,
+
+		/**
+		 * Specifies the given text will be used for semantic textual similarity (STS).
+		 */
+		SEMANTIC_SIMILARITY,
